import { Logger } from '@nestjs/common';
import { algoliasearch } from 'algoliasearch';

import { getEnv } from '@utils/get-env-variable.util';

import {
	ALG_API_KEY,
	ALG_APP_ID,
	ALG_INDEX_NAME,
	CI_BASE_URL,
} from '@constants/env-variables.constant';

import { AlgoliaRelatedProductHit } from '@interfaces/algolia-hits.interface';
import {
	IMMSProductItem,
	IMMSRelatedProductsPayload,
} from '@interfaces/mms-related-products.interface';

// npx ts-node -r dotenv/config -r tsconfig-paths/register ./src/scripts/mms-to-algolia-update.script.ts

const logger = new Logger('mms-to-algolia-update');

const algAppId = getEnv<string>({ key: ALG_APP_ID });
const algApiKey = getEnv<string>({ key: ALG_API_KEY });
const algIndexName = getEnv<string>({ key: ALG_INDEX_NAME });
const mmsBaseUrl = getEnv<string>({ key: CI_BASE_URL });

const client = algoliasearch(algAppId, algApiKey);

const BATCH_SIZE = 1000; // Number of records to process in each batch
const MAX_CONCURRENT_REQUESTS = 10; // Maximum number of concurrent API requests

function extractProductNames({ products }: { products: IMMSProductItem[] }): string[] {
	return products.filter((product) => product.name).map((product) => product.name);
}
async function processBatch({
	products,
}: {
	products: AlgoliaRelatedProductHit[];
}): Promise<void> {
	logger.log(`Processing batch of ${products.length} products`);

	// Process products in chunks to limit concurrent requests
	for (let i = 0; i < products.length; i += MAX_CONCURRENT_REQUESTS) {
		const chunk = products.slice(i, i + MAX_CONCURRENT_REQUESTS);
		const chunkPromises = chunk.map(async (product) => {
			const productId = product.objectID;
			try {
				logger.log(`Processing product ID: ${productId}`);

				const mmsUrl = `${mmsBaseUrl}/products/styles/${productId}/related_styles.json?PK=${productId}`;

				const mmsReq = await fetch(mmsUrl);
				const data = (await mmsReq.json()) as IMMSRelatedProductsPayload | null;
				if (!data) {

