    18→
    19→interface ProductParityReport {
    20→	productId: string;
    21→	mms_alternatives: string[];
    22→	mms_alternatives_count: number;
    23→	new_recomendations: string[];
    24→	new_recomendations_count: number;
    25→	parity: number;
    26→	isParityOk: boolean;
    27→}
    28→
    29→const algAppId = getEnv<string>({ key: ALG_APP_ID });
    30→const algApiKey = getEnv<string>({ key: ALG_API_KEY });
    31→const algIndexName = getEnv<string>({ key: ALG_INDEX_NAME });
    32→
    33→const client = algoliasearch(algAppId, algApiKey);
    34→
    35→const BATCH_SIZE = 1000;
    36→const PARITY_THRESHOLD = 50;
    37→
    38→const logger = new Logger('product-parity-report.script.ts');
    39→
    40→function getParityPercentage(
    41→	mmsAlternatives: string[],
    42→	newRecommendations: string[],
    43→): number {
    44→	const intersection = newRecommendations.filter((rec) => mmsAlternatives.includes(rec));
    45→	const percentage = (intersection.length / mmsAlternatives.length) * 100;
    46→	return percentage;
    47→}
    48→
    49→async function getRelatedProducts(productId: string): Promise<string[]> {
    50→	try {
    51→		const results = await client.initRecommend().getRecommendations({
    52→			requests: [
    53→				{
    54→					indexName: algIndexName,
    55→					model: 'related-products',
    56→					threshold: 0,
    57→					objectID: productId,
    58→				},
    59→			],
    60→		});
    61→
    62→		const recommendations = results.results[0]?.hits ?? [];
    63→
    64→		const newRecommendations = (recommendations as AlgoliaRelatedProductHit[])
    65→			.slice(0, 4)
    66→			.map((hit) => hit.name);
    67→
    68→		return newRecommendations;
    69→	} catch (error: unknown) {
    70→		logger.error(
    71→			`Error fetching related products from Algolia for productId ${productId}`,
    72→			error,
    73→		);
    74→		throw new Error(`Failed to fetch related products for productId ${productId}`);
    75→	}
    76→}
    77→
    78→async function processBatch(
    79→	products: AlgoliaRelatedProductHit[],
    80→): Promise<ProductParityReport[]> {
    81→	logger.log(`Processing batch of ${products.length} products`);
    82→
    83→	const reports: ProductParityReport[] = [];
    84→
    85→	for (const product of products) {
    86→		const productId = product.objectID;
    87→		try {
    88→			logger.log(`Processing product ID: ${productId}`);
    89→
    90→			const newRecommendations = await getRelatedProducts(productId);
    91→			const mmsAlternatives = product.mms_alternatives;
    92→			if (mmsAlternatives.length === 0) {
    93→				logger.log(`Product ID: ${productId} has no MMS alternatives`);
    94→				continue;
    95→			}
    96→
    97→			const parity = getParityPercentage(mmsAlternatives, newRecommendations);
    98→			const isParityOk = parity >= PARITY_THRESHOLD;
    99→
   100→			const data = {
   101→				productId,
   102→				mms_alternatives: mmsAlternatives,
   103→				mms_alternatives_count: mmsAlternatives.length,
   104→				new_recomendations: newRecommendations,
   105→				new_recomendations_count: newRecommendations.length,
   106→				parity,
   107→				isParityOk,
   108→			};
   109→
   110→			logger.log(`Product ID: ${productId} processed successfully`, data);
   111→
   112→			reports.push(data);
   113→		} catch (error) {
   114→			logger.error(`Error processing product ID ${productId}:`, error);
   115→		}
   116→	}
   117→
   118→	logger.log(`Completed chunk: ${products.length} products updated successfully`);
   119→
   120→	return reports;
   121→}
