async function processBatch({
	products,
}: {
	products: AlgoliaRelatedProductHit[];
}): Promise<ProductParityReport[]> {
	logger.log(`Processing batch of ${products.length} products`);

	const reports: ProductParityReport[] = [];

	for (const product of products) {
		const productId = product.objectID;
		try {
			logger.log(`Processing product ID: ${productId}`);

			const newRecommendations = await getRelatedProducts({ productId });
			const mmsAlternatives = product.mms_alternatives;
			if (mmsAlternatives.length === 0) {
				logger.log(`Product ID: ${productId} has no MMS alternatives`);
				continue;
			}

			const parity = getParityPercentage({ mmsAlternatives, newRecommendations });
			const isParityOk = parity >= PARITY_THRESHOLD;

			const data = {
				productId,
				mms_alternatives: mmsAlternatives,
				mms_alternatives_count: mmsAlternatives.length,
				new_recomendations: newRecommendations,
				new_recomendations_count: newRecommendations.length,
				parity,
				isParityOk,
			};

			logger.log(`Product ID: ${productId} processed successfully`, data);

			reports.push(data);
		} catch (error) {
			logger.error(`Error processing product ID ${productId}:`, error);
		}
	}

	logger.log(`Completed chunk: ${products.length} products updated successfully`);

	return reports;
}

void (async () => {
	logger.log(
		'Starting update for all products in Algolia index with MMS alternatives and complements',
	);

	let page = 0;
	let totalProcessed = 0;
	let hasMorePages = true;

	const allProducts: AlgoliaRelatedProductHit[] = [];

	while (hasMorePages) {
		const browse = await client.browse({
			indexName: algIndexName,
			browseParams: {
				query: '',
				hitsPerPage: BATCH_SIZE,
				page,
			},
		});
		const products = browse.hits as AlgoliaRelatedProductHit[];
		logger.log(`Found ${products.length} products`);
		allProducts.push(...products);
		if (products.length < BATCH_SIZE) {
			hasMorePages = false;
		}
		page++;
		totalProcessed += products.length;
	}

	logger.log(`Total products processed: ${totalProcessed}`);

	const reports = await processBatch({ products: allProducts });

	logger.log(`Update process completed. Total products processed: ${reports.length}`);

	const timestamp = new Date().toISOString().replace(/:/g, '-').split('.')[0] ?? '';
	const filename = `parity-report-${algIndexName}-${timestamp}.json`;

