import * as fs from 'fs';
import * as path from 'path';

import { Logger } from '@nestjs/common';
import { algoliasearch } from 'algoliasearch';

import { getEnv } from '@utils/get-env-variable.util';

import {
	ALG_API_KEY,
	ALG_APP_ID,
	ALG_INDEX_NAME,
} from '@constants/env-variables.constant';

import { AlgoliaRelatedProductHit } from '@interfaces/algolia-hits.interface';

// npx ts-node -r dotenv/config -r tsconfig-paths/register ./src/scripts/product-parity-report.script.ts

interface ProductParityReport {
	productId: string;
	mms_alternatives: string[];
	mms_alternatives_count: number;
	new_recomendations: string[];
	new_recomendations_count: number;
	parity: number;
	isParityOk: boolean;
}

const algAppId = getEnv<string>({ key: ALG_APP_ID });
const algApiKey = getEnv<string>({ key: ALG_API_KEY });
const algIndexName = getEnv<string>({ key: ALG_INDEX_NAME });

const client = algoliasearch(algAppId, algApiKey);

const BATCH_SIZE = 1000;
const PARITY_THRESHOLD = 50;

const logger = new Logger('product-parity-report.script.ts');

function getParityPercentage({
	mmsAlternatives,
	newRecommendations,
}: {
	mmsAlternatives: string[];
	newRecommendations: string[];
}): number {
	const intersection = newRecommendations.filter((rec) => mmsAlternatives.includes(rec));
	const percentage = (intersection.length / mmsAlternatives.length) * 100;
	return percentage;
}

async function getRelatedProducts({
	productId,
}: {
	productId: string;
}): Promise<string[]> {
	try {
		const results = await client.initRecommend().getRecommendations({
			requests: [
				{
					indexName: algIndexName,
					model: 'related-products',
					threshold: 0,
					objectID: productId,
				},
			],
		});

		const recommendations = results.results[0]?.hits ?? [];

		const newRecommendations = (recommendations as AlgoliaRelatedProductHit[])
			.slice(0, 4)
			.map((hit) => hit.name);

		return newRecommendations;
	} catch (error: unknown) {
		logger.error(
			`Error fetching related products from Algolia for productId ${productId}`,
			error,
		);
		throw new Error(`Failed to fetch related products for productId ${productId}`);
	}
}

