import { RGBColor } from 'color-diff';

import { IProductColor } from '@interfaces/algolia-hits.interface';

export function getColorRGBToIdHash({
	colors,
}: {
	colors: IProductColor[];
}): Record<string, number> {
	return colors.reduce<Record<string, number>>((acc, color) => {
		if (color.rbgs?.[0]) {
			acc[convertRGBToString({ rgb: color.rbgs[0] })] = color.id;
		}
		return acc;
	}, {});
}

export function convertRGBToString({ rgb }: { rgb: RGBColor }): string {
	return `R:${rgb.R},G:${rgb.G},B:${rgb.B}`;
}

export function convertStringToRGB({ str }: { str: string }): RGBColor {
	const [R, G, B] = str.split(',');
	return {
		R: Number(R?.split(':')[1]),
		G: Number(G?.split(':')[1]),
		B: Number(B?.split(':')[1]),
	};
}

