				const result = await handler(item);
				queue.push({ type: 'result', result, item });
			} catch (error) {
				queue.push({ type: 'error', error, item });
			}

			if (resolveWaiting) {
				resolveWaiting();
				resolveWaiting = null;
			}
		}

		activeWorkers--;
		if (activeWorkers === 0) {
			done = true;
			if (resolveWaiting) {
				resolveWaiting();
				resolveWaiting = null;
			}
		}
	}

